import "core-js/modules/es.array.push.js";
import { ref, reactive } from 'vue';
import { useStore } from 'vuex';
import { useRouter, useRoute } from 'vue-router';
import { ElMessage } from 'element-plus';
import { User, Lock } from '@element-plus/icons-vue';
export default {
  name: 'LoginView',
  components: {
    User,
    Lock
  },
  setup() {
    const store = useStore();
    const router = useRouter();
    const route = useRoute();
    const loginFormRef = ref(null);
    const loginForm = reactive({
      username: '',
      password: ''
    });
    const rememberMe = ref(false);
    const loading = ref(false);
    const errorMessage = ref('');
    const loginRules = {
      username: [{
        required: true,
        message: '请输入用户名',
        trigger: 'blur'
      }, {
        min: 3,
        max: 20,
        message: '用户名长度应在3-20个字符之间',
        trigger: 'blur'
      }],
      password: [{
        required: true,
        message: '请输入密码',
        trigger: 'blur'
      }, {
        min: 6,
        max: 40,
        message: '密码长度应在6-40个字符之间',
        trigger: 'blur'
      }]
    };
    const handleLogin = () => {
      loginFormRef.value.validate(valid => {
        if (valid) {
          loading.value = true;
          errorMessage.value = '';
          const loginData = {
            username: loginForm.username,
            password: loginForm.password
          };
          store.dispatch('auth/login', loginData).then(() => {
            ElMessage.success('登录成功!');

            // 获取用户信息
            const user = store.getters['auth/currentUser'];

            // 检查是否有重定向地址
            const redirectPath = route.query.redirect;

            // 根据用户角色决定跳转页面
            if (user && user.roles) {
              // 如果有重定向地址则使用重定向地址
              if (redirectPath) {
                router.push(redirectPath);
              }
              // 如果用户是管理员，跳转到管理员仪表盘
              else if (user.roles.includes('ROLE_ADMIN')) {
                router.push('/admin/dashboard');
              } else {
                // 普通用户跳转到首页
                router.push('/');
              }
            } else {
              // 角色信息不存在，跳转到首页或重定向页面
              router.push(redirectPath || '/');
            }
          }).catch(error => {
            console.log('登录界面捕获到错误:', error);

            // 处理账号禁用的错误消息
            if (error.isDisabledAccount || error.message && error.message.includes('禁用')) {
              errorMessage.value = '账号已被禁用，请联系管理员';
              return;
            }

            // 处理密码错误
            if (error.response && error.response.status === 401) {
              errorMessage.value = '用户名或密码错误';
              return;
            }

            // 处理服务器返回的其他明确错误信息
            if (error.response && error.response.data) {
              const responseData = error.response.data;
              let responseMsg = '';
              if (typeof responseData === 'string') {
                responseMsg = responseData;
              } else if (responseData.message) {
                responseMsg = responseData.message;
              } else if (responseData.error) {
                responseMsg = responseData.error;
              }
              if (responseMsg) {
                errorMessage.value = responseMsg;
                return;
              }
            }

            // 默认错误消息
            errorMessage.value = '登录失败，请稍后再试';
            console.error('登录失败:', error);
          }).finally(() => {
            loading.value = false;
          });
        } else {
          return false;
        }
      });
    };
    return {
      loginForm,
      loginRules,
      rememberMe,
      loading,
      errorMessage,
      handleLogin,
      loginFormRef
    };
  }
};
